const webhookData = $('Webhook Trigger').first().json;
const b = webhookData.body ?? webhookData;
const run_id = b.run_id || b.runId || b.runID;
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!run_id) {
  return [{ json: { ok: false, run_id: null, error: { code: 'MISSING_FIELDS', message: 'run_id is required' } } }];
}

if (b.workflow_key !== 'grant_enrich') {
  return [{ json: { ok: false, run_id, error: { code: 'WRONG_WORKFLOW', message: 'workflow_key must be grant_enrich, got: ' + b.workflow_key } } }];
}

if (!b.entity_id || typeof b.entity_id !== 'string' || !UUID_RE.test(b.entity_id)) {
  return [{ json: { ok: false, run_id, error: { code: 'INVALID_ENTITY_ID', message: 'entity_id must be a valid UUID' } } }];
}

if (!b.source_url || typeof b.source_url !== 'string') {
  return [{ json: { ok: false, run_id, error: { code: 'MISSING_URL', message: 'source_url is required' } } }];
}

return [{ json: {
  ok: true,
  run_id,
  workflow_key: 'grant_enrich',
  entity_id: b.entity_id,
  entity_type: 'grant',
  source_url: b.source_url,
  grant_name: b.grant_name || 'Unknown Grant'
} }];

const input = $('Normalize Input').first().json;
let scrapeData;
try {
  scrapeData = $('Firecrawl Scrape').first().json;
} catch (e) {
  return [{ json: { ...input, markdown: '', links: [], scrape_ok: false, scrape_bytes: 0, scrape_error: 'Firecrawl node failed: ' + String(e.message).slice(0, 200) } }];
}

if (scrapeData.error || !scrapeData.success) {
  return [{ json: { ...input, markdown: '', links: [], scrape_ok: false, scrape_bytes: 0, scrape_error: String(scrapeData.error || 'Firecrawl returned unsuccessful response').slice(0, 500) } }];
}

const markdown = scrapeData.data?.markdown || scrapeData.markdown || '';
const links = scrapeData.data?.links || scrapeData.links || [];

// Truncate to ~30k chars for LLM context window
const truncated = markdown.length > 30000 ? markdown.slice(0, 30000) + '\n[TRUNCATED]' : markdown;

return [{ json: { ...input, markdown: truncated, links, scrape_ok: true, scrape_bytes: markdown.length } }];

