const input = $('Prepare LLM Input').first().json;
let llmOutput;
try {
  llmOutput = $('AI Extract Grant Data').first().json;
} catch (e) {
  return [{ json: { ...input, enrichment: {}, llm_error: 'LLM node failed: ' + String(e.message).slice(0, 200) } }];
}

// The structured output parser returns the parsed object directly
let enrichment = {};
try {
  // Agent node may wrap in output or return directly
  if (llmOutput && typeof llmOutput === 'object') {
    enrichment = llmOutput.output ? (typeof llmOutput.output === 'string' ? JSON.parse(llmOutput.output) : llmOutput.output) : llmOutput;
  }
} catch (e) {
  return [{ json: { ...input, enrichment: {}, llm_error: 'Failed to parse LLM output: ' + String(e.message).slice(0, 200) } }];
}

// Validate arrays
if (!Array.isArray(enrichment.important_dates)) enrichment.important_dates = [];
if (!Array.isArray(enrichment.resources)) enrichment.resources = [];
if (!Array.isArray(enrichment.downloads)) enrichment.downloads = [];

return [{ json: { ...input, enrichment, llm_error: null } }];

let input;
try {
  input = $('Parse LLM Output').first().json;
} catch (e) {
  input = $('Prepare LLM Input').first().json;
}

const enrichment = input.enrichment || {};
const scrapeOk = input.scrape_ok || false;
const status = (scrapeOk && !input.llm_error) ? 'success' : (scrapeOk ? 'success' : 'no_data');

return [{ json: {
  run_id: input.run_id,
  workflow: 'grant_enrich',
  status,
  entity_type: 'grant',
  entity_id: input.entity_id,
  source_url: input.source_url,
  scrape: { ok: scrapeOk, bytes: input.scrape_bytes || 0 },
  enrichment,
  error: input.scrape_error ? { code: 'SCRAPE_FAILED', message: input.scrape_error } : (input.llm_error ? { code: 'LLM_FAILED', message: input.llm_error } : null),
  occurred_at: new Date().toISOString()
} }];

const input = $('Prepare LLM Input').first().json;
return [{ json: {
  run_id: input.run_id,
  workflow: 'grant_enrich',
  status: 'no_data',
  entity_type: 'grant',
  entity_id: input.entity_id,
  source_url: input.source_url,
  scrape: { ok: false, bytes: 0 },
  enrichment: {},
  error: { code: 'SCRAPE_FAILED', message: input.scrape_error || 'Unknown scrape error' },
  occurred_at: new Date().toISOString()
} }];
